VALUES
  ('cpa-moex-00635', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員溝通內部控制缺失時，下列敘述何者錯誤？', '["管理階層未能改正先前已溝通之其他缺失，可能構成一項顯著缺失而須與治理單位溝通", "如內部稽核人員曾與管理階層溝通內部控制其他缺失，則查核人員無須重複溝通", "如查核人員已就其發現與管理階層討論攸關事實與情況，則可視為已與管理階層口頭溝通 內部控制其他缺失", "對內部控制顯著缺失採行改正行動之成本與效益評估，係屬查核人員之責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00636', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何種情況存在時，查核人員建立單一金額估計或金額區間估計以評估管理階層單一金額 估計，係屬較適當之因應對策？', '["會計估計非由受查者會計系統之例行性資料處理所產生", "查核人員複核前期之類似會計估計後，認為管理階層當期之會計估計程序可能為有效", "受查者對會計估計程序之控制係妥善設計或付諸實行", "財務報導期間結束日後至查核報告日間發生之事項或交易，與管理階層之單一金額估計一致"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00637', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關會計估計之敘述何者正確？', '["對未於財務報表中認列或揭露之會計估計，客戶出具之書面聲明可能包括管理階層判斷會 計估計未符合認列或揭露條件之基礎係屬適當之聲明事項", "查核人員如判斷某一會計估計存有顯著風險，應瞭解與該風險攸關之內部控制，尤其是控 制作業", "查核人員於複核前期會計估計時，若發現最終結果與認列於前期財務報表金額間存有差異， 則表示前期財務報表存有不實表達", "當查核人員認為未認列會計估計係屬適當，而管理階層於財務報表附註已揭露未認列會計 估計，必要時會計師可能於查核報告中增加其他事項段提醒財務報表使用者注意該重大不 確定性。 ⑤敏感度分析可能顯示會計估計對某些假設特別敏感，則該等假設可能被視為重大，此時查 核人員應特別注意該等假設"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00638', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關受查者存貨實地盤點之敘述，下列何者正確？① 盤點日期宜選接近期末，並按預擬之盤', '["盤點日前應由倉管以外人員進行預盤", "使用預先連續編號之盤點標籤，由 初盤人員填寫後黏貼於存貨上，再由複盤人員負責驗證", "盤點期間宜儘量停止存貨之入庫 及出庫", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00639', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列電腦輔助查核技術（computer-assistedaudittechniques,CAAT）於進行控制測試時，何者 會在受查者的操作人員不知情之情況下，同時處理真實及測試的交易？', '["平行模擬（parallelsimulation）法", "測試資料（testdata）法", "整體測試設施（integratedtestfacility）法", "嵌入式查核模組（embeddedauditmodule）法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00640', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '針對訴訟與索賠之查核，下列敘述何者錯誤？', '["查核人員應寄送由管理階層具名之查詢函，以要求外部法律顧問與查核人員直接溝通", "外部法律顧問拒絕回覆時，查核人員得要求管理階層提供相關書面聲明作為替代性程序", "查核人員與外部法律顧問會面通常須經管理階層同意，且有管理階層之代表出席", "查核人員可能藉由查詢或自外部法律顧問取得截至查核報告日與訴訟及索賠現況有關之查 核證據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00641', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '績效審計係審計機關對各機關運用公共資源有關經濟性、效率性與效益性的查核，請指出下 列事項何者係屬效率性之範疇？', '["購買原物料程序是否符合政府採購法規定", "醫院是否以最低價格購買物料", "在未增加成本及維持既定服務品質下，病患等候時間是否縮短", "改善管理作業後，是否對民眾服務產生正面影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00642', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何者較不可能為財務報表查核工作僅能提供高度但非絕對確信之原因？', '["查核時間的限制", "會計準則上的限制", "查核程序上的限制", "人員訓練時間的限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00643', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據審計準則公報第46號「會計師事務所之品質管制」規定，下列何者係屬會計師事務所品', '["事務所領導階層對品質管制之責任", "查核案件之複核", "職業道德規範", "人力資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00644', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據審計準則公報第67號之規定，查核人員評估非正常營運之重大關係人交易之動機及合理 性時，最不可能考量下列何項？', '["可能涉及多個關係人", "交易缺乏明顯合理之商業理由", "必須依據交易合約及法律形式進行會計處理", "不尋常之交易價格、利率、保證及償還期限，且以不尋常方式進行交易"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00645', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關採用查核人員專家之工作，下列敘述何者正確？', '["查核人員外部專家並非查核團隊之成員，未受會計師事務所品質管制政策規範，因此查核 人員無須評估查核人員外部專家是否遵循與獨立性有關之規範", "查核人員外部專家之工作底稿係該專家所有，且不構成查核工作底稿之一部分", "會計師得於無保留意見之查核報告之查核意見段提及查核人員專家之工作，以協助使用者 瞭解專家參與之工作，以及區分專家與會計師之責任", "查核人員在會計或審計以外之某一領域非屬專家，查核人員不得於無查核人員專家協助之 情況下執行相關之查核工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00646', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '會計師如採用查核人員專家之工作作為查核證據時，有關查核報告的撰寫，下列那一項的做 法適當？', '["於無保留意見之查核報告中，增加其他事項段說明查核人員專家工作之採用", "於無保留意見之查核報告中，增加強調事項段說明查核人員專家工作之採用", "於保留意見之查核報告中之保留意見之基礎段中，提及查核人員專家之工作，以協助使用 者瞭解導致修正式意見之事項，並指出提及專家之工作並未減輕會計師對財務報表所表示 查核意見之責任", "於保留意見之查核報告中增加其他事項段說明查核人員專家工作之採用，並指出提及專家 之工作並未減輕會計師對財務報表所表示查核意見之責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00647', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員考量重大性決策時，下列相關敘述何者錯誤？', '["查核人員必須站在財務報表使用者的立場，而非查核人員的立場考量重大性", "查核人員可合理假設財務報表使用者為一般對商業與經濟活動及會計具有合理認知的社會 大眾", "查核人員選定重大性基準時，一定要以實帳戶為基準", "百分比之決定與所選用之基準間存有密切的關聯性，通常選定基準的金額越大，其適用之 百分比越低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00648', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員應與受查者治理單位溝通之事項包括：① 查核時所遭遇之重大困難  ②查核時所辨', '["查核時所發現與受查者關係人有關之重大事項", "查核時發現所 聘任之查核人員專家的工作不適當", "僅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00649', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '我國審計準則公報對查核人員財務報表查核工作之規劃，經由對受查者及其環境（包括內部 控制）之瞭解，以辨認並評估財務報表重大不實表達風險與其應設計及執行之因應對策等均 有規範，惟對小規模受查者有特別考量。下列相關敘述何者錯誤？', '["小規模受查者可能使用較為簡易之方法、流程及程序，以達成其內部控制目標", "為查核小規模受查者所訂定之整體查核策略，無須過於複雜或耗時，可依據受查者之規模、 查核之複雜度及查核團隊之大小而有所不同", "小規模受查者之繼續營業單位稅前淨利如持續偏低，例如所有者兼管理者以稅前淨利之大 部分作為其酬勞，則以減除酬勞前之稅前淨利作為重大性基準可能較為攸關", "對小規模受查者而言，查核人員可辨認出之控制作業可能不多，於執行進一步查核程序雖 以證實程序為主，但均可取得足夠及適切之查核證據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00650', 'cpa', 'cpa-moex-109-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員採用機率與大小成比例（PPS）抽樣法推估應收帳款帳載可能的不實表達金額，應收 帳款帳上金額為$4,000,000，抽樣區間為$20,000。若抽查結果發現三項錯誤，分別為帳面金額 $25,000，查核金額為$15,000；帳面金額$10,000，查核金額為$7,000；以及帳面金額$5,000， 查核金額為$4,000。則應收帳款的預期的不實表達金額（projectedmisstatement）為若干？', '["$14,000", "$15,000", "$18,000", "$20,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:08+00:00", "source_pdf_sha1": "7602cf0a08b3", "answer_pdf_sha1": "96f45fb26fe3", "source_family": "moex-gov-tw", "moex": {"exam_code": "109140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "109", "exam_name": "109年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
